import clsx from "clsx";
import { Activity, Clock, FileText, Files, Globe2, List, Loader2, X } from "lucide-react";
import { useEffect, useMemo, useState } from "react";
import type { ReactElement } from "react";
import type { RendererRunEvent, RunStatus } from "@shared/types";
import { MarkdownBlock } from "./MarkdownBlock";
import { useShortcutOverlay } from "../lib/keyboardShortcuts";
import {
  agentEventLabel,
  agentEventText,
  agentEventTone,
  deriveAgentProgress,
  isAgentSessionActive,
  isMarkdownAgentEvent,
  sortAgentEvents
} from "../lib/agentProgress";

type CopyHandlers = {
  onCopied?: (kind: "markdown" | "code") => void;
  onCopyError?: (error: unknown) => void;
};

type AgentProgressSummaryProps = {
  events: RendererRunEvent[];
  status: RunStatus;
  startedAt?: string | null;
  endedAt?: string | null;
  metricsAvailable?: boolean;
  now?: number;
};

const useProgressNow = (active: boolean, now?: number): number => {
  const [currentNow, setCurrentNow] = useState(() => now ?? Date.now());

  useEffect(() => {
    if (now !== undefined) {
      setCurrentNow(now);
      return undefined;
    }
    if (!active) {
      setCurrentNow(Date.now());
      return undefined;
    }
    const interval = window.setInterval(() => setCurrentNow(Date.now()), 1000);
    return () => window.clearInterval(interval);
  }, [active, now]);

  return now ?? currentNow;
};

const formatTimestamp = (timestamp: string): string =>
  new Date(timestamp).toLocaleTimeString([], { hour: "2-digit", minute: "2-digit", second: "2-digit" });

const metricValue = (value: number | null): string => (value === null ? "Unavailable" : String(value));

export function AgentProgressSummary({
  events,
  status,
  startedAt,
  endedAt,
  metricsAvailable,
  now
}: AgentProgressSummaryProps): ReactElement {
  const active = isAgentSessionActive(status);
  const currentNow = useProgressNow(active, now);
  const progress = useMemo(
    () => deriveAgentProgress({ events, status, startedAt, endedAt, now: currentNow, metricsAvailable }),
    [currentNow, endedAt, events, metricsAvailable, startedAt, status]
  );

  return (
    <div className={clsx("agent-progress", progress.statusTone)} data-status={status}>
      <div className="agent-progress-main">
        <span className="agent-progress-icon">
          <Activity size={16} />
        </span>
        <div>
          <strong>{progress.statusLabel}</strong>
          <span>{progress.statusDetail}</span>
        </div>
      </div>

      <div className="agent-metrics" aria-label="Agent progress metrics">
        <div className="agent-metric">
          <Clock size={15} />
          <span>Elapsed</span>
          <strong>{progress.elapsedLabel}</strong>
        </div>
        <div className="agent-metric">
          <Files size={15} />
          <span>Files Edited</span>
          <strong>{metricValue(progress.filesEdited)}</strong>
        </div>
        <div className="agent-metric">
          <Globe2 size={15} />
          <span>Web Searches</span>
          <strong>{metricValue(progress.webSearches)}</strong>
        </div>
      </div>

      <div className="agent-progress-foot">
        <span>{progress.totalEvents > 0 ? `${progress.totalEvents} event${progress.totalEvents === 1 ? "" : "s"}` : "No events recorded"}</span>
        {progress.lastEventAt && <span>Last update {formatTimestamp(progress.lastEventAt)}</span>}
      </div>
    </div>
  );
}

export function AgentActivityPanel({
  events,
  status,
  runId,
  logLoading,
  logError,
  onOpenLogs,
  onRevealFile
}: {
  events: RendererRunEvent[];
  status: RunStatus;
  runId: string | null;
  logLoading: boolean;
  logError: string | null;
  onOpenLogs: () => void;
  onRevealFile: () => void;
}): ReactElement {
  const recentEvents = useMemo(
    () =>
      sortAgentEvents(events)
        .filter((event) => event.type !== "command.output")
        .slice(-4),
    [events]
  );

  return (
    <section className="agent-activity-panel">
      <header>
        <h3>Agent Activity</h3>
        <div className="agent-panel-actions">
          <button onClick={onOpenLogs} disabled={!runId && events.length === 0}>
            <List size={14} />
            Open Logs
          </button>
          <button onClick={onRevealFile}>
            <FileText size={14} />
            File
          </button>
        </div>
      </header>

      <AgentProgressSummary events={events} status={status} metricsAvailable={events.length > 0} />

      <div className="agent-recent">
        <div className="agent-recent-title">
          <span>Recent Activity</span>
          {logLoading && (
            <span className="agent-inline-state">
              <Loader2 className="spin" size={13} />
              Loading saved events
            </span>
          )}
        </div>
        {logError && <div className="agent-state error">Unable to load saved logs: {logError}</div>}
        {!logLoading && recentEvents.length === 0 && <div className="agent-state empty">No run events have been recorded for this session.</div>}
        {recentEvents.length > 0 && (
          <div className="agent-recent-list">
            {recentEvents.map((event, index) => (
              <div className={clsx("agent-recent-row", agentEventTone(event))} key={`${event.runId}-${event.timestamp}-${event.type}-${index}`}>
                <span>{formatTimestamp(event.timestamp)}</span>
                <strong>{agentEventLabel(event)}</strong>
                <p>{agentEventText(event)}</p>
              </div>
            ))}
          </div>
        )}
      </div>
    </section>
  );
}

const renderEventDetails = (event: RendererRunEvent, handlers: CopyHandlers): ReactElement => {
  const text = agentEventText(event);
  if (isMarkdownAgentEvent(event)) {
    return (
      <MarkdownBlock
        className="agent-log-markdown"
        source={text}
        compact
        onCopied={handlers.onCopied}
        onCopyError={handlers.onCopyError}
      />
    );
  }

  return <pre>{text || "No details."}</pre>;
};

export function AgentLogViewer({
  events,
  loading,
  error,
  title,
  onClose,
  onCopied,
  onCopyError
}: {
  events: RendererRunEvent[];
  loading: boolean;
  error: string | null;
  title: string;
  onClose: () => void;
} & CopyHandlers): ReactElement {
  const orderedEvents = useMemo(() => sortAgentEvents(events), [events]);
  useShortcutOverlay({
    id: "agent-log-viewer",
    priority: 110,
    onEscape: () => {
      onClose();
      return true;
    }
  });

  return (
    <div className="modal-backdrop agent-log-backdrop">
      <section className="modal agent-log-modal" role="dialog" aria-modal="true" aria-labelledby="agent-log-title">
        <header>
          <div>
            <h2 id="agent-log-title">{title}</h2>
            <p>{orderedEvents.length} event{orderedEvents.length === 1 ? "" : "s"} in chronological order</p>
          </div>
          <button className="icon-button" onClick={onClose} aria-label="Close agent log viewer">
            <X size={18} />
          </button>
        </header>

        {loading && (
          <div className="agent-log-state loading">
            <Loader2 className="spin" size={16} />
            Loading saved log events
          </div>
        )}
        {error && <div className="agent-log-state error">Unable to load saved log events: {error}</div>}
        {!loading && !error && orderedEvents.length === 0 && <div className="agent-log-state empty">No detailed log events are available.</div>}

        {orderedEvents.length > 0 && (
          <ol className="agent-log-list">
            {orderedEvents.map((event, index) => (
              <li className={clsx("agent-log-item", agentEventTone(event))} key={`${event.runId}-${event.timestamp}-${event.type}-${index}`}>
                <div className="agent-log-meta">
                  <time dateTime={event.timestamp}>{formatTimestamp(event.timestamp)}</time>
                  <span>{agentEventLabel(event)}</span>
                  <code>{event.type}</code>
                </div>
                <div className="agent-log-content">{renderEventDetails(event, { onCopied, onCopyError })}</div>
              </li>
            ))}
          </ol>
        )}
      </section>
    </div>
  );
}

import type { RendererRunEvent, RunStatus } from "@shared/types";

export type AgentProgressStatus = RunStatus;

export type AgentProgressMetrics = {
  elapsedMs: number | null;
  elapsedLabel: string;
  filesEdited: number | null;
  webSearches: number | null;
  totalEvents: number;
  startedAt: string | null;
  endedAt: string | null;
  lastEventAt: string | null;
  statusLabel: string;
  statusDetail: string;
  statusTone: "idle" | "active" | "success" | "warning" | "danger";
  active: boolean;
  metricsAvailable: boolean;
};

export type AgentProgressInput = {
  events: RendererRunEvent[];
  status: AgentProgressStatus;
  startedAt?: string | null;
  endedAt?: string | null;
  now?: number;
  metricsAvailable?: boolean;
};

const pad2 = (value: number): string => String(value).padStart(2, "0");

const timestampMs = (timestamp?: string | null): number | null => {
  if (!timestamp) return null;
  const parsed = Date.parse(timestamp);
  return Number.isNaN(parsed) ? null : parsed;
};

const eventTime = (event: RendererRunEvent): number => timestampMs(event.timestamp) ?? 0;

export const isAgentSessionActive = (status: AgentProgressStatus): boolean => status === "running" || status === "drafting";

export const formatElapsedDuration = (durationMs: number | null): string => {
  if (durationMs === null) return "Unavailable";
  const totalSeconds = Math.max(0, Math.floor(durationMs / 1000));
  const seconds = totalSeconds % 60;
  const totalMinutes = Math.floor(totalSeconds / 60);
  const minutes = totalMinutes % 60;
  const hours = Math.floor(totalMinutes / 60);
  return hours > 0 ? `${hours}:${pad2(minutes)}:${pad2(seconds)}` : `${pad2(minutes)}:${pad2(seconds)}`;
};

export const isWebSearchEvent = (event: RendererRunEvent): boolean =>
  event.type === "web.search" || (event.type === "agent.message.delta" && /^web search:/i.test(event.text.trim()));

export const agentEventText = (event: RendererRunEvent): string => {
  switch (event.type) {
    case "run.started":
      return `Run started (${event.threadId})`;
    case "agent.message.delta":
    case "agent.message.completed":
      return event.text;
    case "command.started":
      return `$ ${event.command}`;
    case "command.output":
      return event.text;
    case "command.completed":
      return `Command ${event.status}`;
    case "file.change":
      return event.summary ?? event.path;
    case "web.search":
      return `Web search: ${event.query}`;
    case "approval.requested":
      return `Approval requested: ${event.kind}`;
    case "approval.resolved":
      return `Approval ${event.decision}`;
    case "ticket.status_changed":
      return `Status moved from ${event.fromStatus} to ${event.toStatus}`;
    case "clarification.requested":
      return `${event.questions.length} clarification question${event.questions.length === 1 ? "" : "s"} requested`;
    case "run.completed":
      return event.finalResponse;
    case "run.failed":
      return event.message;
    default:
      return "";
  }
};

export const isMarkdownAgentEvent = (event: RendererRunEvent): boolean =>
  event.type === "agent.message.completed" || event.type === "run.completed";

export const agentEventLabel = (event: RendererRunEvent): string => {
  switch (event.type) {
    case "run.started":
    case "run.completed":
    case "run.failed":
      return "Run";
    case "agent.message.delta":
    case "agent.message.completed":
      return isWebSearchEvent(event) ? "Web Search" : "Message";
    case "command.started":
    case "command.output":
    case "command.completed":
      return "Command";
    case "file.change":
      return "File";
    case "web.search":
      return "Web Search";
    case "approval.requested":
    case "approval.resolved":
      return "Approval";
    case "ticket.status_changed":
      return "Status";
    case "clarification.requested":
      return "Clarification";
    default:
      return "Event";
  }
};

export const agentEventTone = (event: RendererRunEvent): "neutral" | "success" | "warning" | "danger" | "info" => {
  if (event.type === "run.failed" || (event.type === "command.completed" && event.status === "failed")) return "danger";
  if (event.type === "run.completed" || (event.type === "command.completed" && event.status === "completed")) return "success";
  if (event.type === "clarification.requested" || event.type === "approval.requested") return "warning";
  if (isWebSearchEvent(event) || event.type === "file.change" || event.type === "ticket.status_changed") return "info";
  return "neutral";
};

export const sortAgentEvents = (events: RendererRunEvent[]): RendererRunEvent[] =>
  events
    .map((event, index) => ({ event, index }))
    .sort((a, b) => eventTime(a.event) - eventTime(b.event) || a.index - b.index)
    .map(({ event }) => event);

export const mergeRunEvents = (...eventGroups: RendererRunEvent[][]): RendererRunEvent[] => {
  const merged = new Map<string, RendererRunEvent>();
  for (const event of eventGroups.flat()) {
    const key = `${event.runId}|${event.timestamp}|${event.type}|${agentEventText(event)}`;
    if (!merged.has(key)) merged.set(key, event);
  }
  return sortAgentEvents([...merged.values()]);
};

const statusCopy = (
  status: AgentProgressStatus
): Pick<AgentProgressMetrics, "statusLabel" | "statusDetail" | "statusTone"> => {
  switch (status) {
    case "drafting":
      return { statusLabel: "Drafting", statusDetail: "Codex is preparing a ticket draft.", statusTone: "active" };
    case "running":
      return { statusLabel: "Active", statusDetail: "Codex is working on this ticket.", statusTone: "active" };
    case "blocked":
      return { statusLabel: "Needs input", statusDetail: "Codex is waiting on clarification.", statusTone: "warning" };
    case "failed":
      return { statusLabel: "Failed", statusDetail: "The agent session ended with an error.", statusTone: "danger" };
    case "completed":
      return { statusLabel: "Completed", statusDetail: "The latest agent session has finished.", statusTone: "success" };
    case "cancelled":
      return { statusLabel: "Cancelled", statusDetail: "The latest agent session was stopped.", statusTone: "danger" };
    case "idle":
    default:
      return { statusLabel: "Inactive", statusDetail: "No agent session is currently active.", statusTone: "idle" };
  }
};

export const deriveAgentProgress = ({
  events,
  status,
  startedAt,
  endedAt,
  now = Date.now(),
  metricsAvailable
}: AgentProgressInput): AgentProgressMetrics => {
  const sorted = sortAgentEvents(events);
  const active = isAgentSessionActive(status);
  const firstEvent = sorted[0] ?? null;
  const lastEvent = sorted.at(-1) ?? null;
  const runStarted = sorted.find((event) => event.type === "run.started") ?? null;
  const terminalEvent =
    [...sorted].reverse().find((event) => event.type === "run.completed" || event.type === "run.failed" || event.type === "clarification.requested") ??
    null;

  const effectiveStartedAt = startedAt ?? runStarted?.timestamp ?? firstEvent?.timestamp ?? null;
  const effectiveEndedAt = endedAt ?? (active ? null : terminalEvent?.timestamp ?? lastEvent?.timestamp ?? null);
  const startMs = timestampMs(effectiveStartedAt);
  const endMs = active ? now : timestampMs(effectiveEndedAt);
  const elapsedMs = startMs !== null && endMs !== null ? Math.max(0, endMs - startMs) : null;
  const haveMetrics = metricsAvailable ?? sorted.length > 0;
  const filesEdited = haveMetrics ? new Set(sorted.filter((event) => event.type === "file.change").map((event) => event.path)).size : null;
  const webSearches = haveMetrics ? sorted.filter(isWebSearchEvent).length : null;

  return {
    ...statusCopy(status),
    active,
    elapsedMs,
    elapsedLabel: formatElapsedDuration(elapsedMs),
    filesEdited,
    webSearches,
    totalEvents: sorted.length,
    startedAt: effectiveStartedAt,
    endedAt: effectiveEndedAt,
    lastEventAt: lastEvent?.timestamp ?? null,
    metricsAvailable: haveMetrics
  };
};

import test from "node:test";
